fixed_code:
method IsDecimalNumberWithPrecision2(s: string) returns (result: bool)
    ensures result <==> (exists dotIndex :: 0 <= dotIndex < |s| && s[dotIndex] == '.' &&        //后置条件1：  存在一个小数点位置 dotIndex，并且符合字符串的索引；
                        (forall i :: 0 <= i < dotIndex ==> '0' <= s[i] <= '9') &&               //后置条件2：  小数点前的所有字符都是数字；
                        (forall i :: dotIndex + 1 <= i < |s| ==> '0' <= s[i] <= '9') &&         //后置条件3：  小数点后的所有字符都是数字；
                        |s| > 0 &&                                                              //后置条件4：  字符串非空；
                        (if |s| > 1 then ('0' <= s[0] <= '9') else false) &&                    //后置条件5：  首位字符合法（不能是符号或字母）；
                        |s| - (dotIndex + 1) == 2)                                              //后置条件6：  小数点后只有 2 位小数
{
    result := false;
    var dotIndex := -1;
    var decimalDigits := 0;
    var i := 0;
    while i < |s|
        invariant 0 <= i <= |s|                                                               //下标不越界
        invariant dotIndex == -1 || (0 <= dotIndex < i && s[dotIndex] == '.')                 //对应后置条件1  
        invariant forall j :: 0 <= j < i ==>                                                  //对应后置条件2、3、5  
            (s[j] == '.' ==> j == dotIndex) && 
            (s[j] != '.' ==> '0' <= s[j] <= '9')
        invariant if dotIndex != -1 then                                                      //对应后置条件6
            decimalDigits == (i - (dotIndex + 1)) 
        else 
            decimalDigits == 0
        invariant 0 <= decimalDigits <= 2                                                      //对应后置条件6
        decreases |s| - i
    {
        if s[i] == '.' {
            if dotIndex != -1 {
                break;
            }
            dotIndex := i;
        } else if '0' <= s[i] <= '9' {
            if dotIndex != -1 {
                decimalDigits := decimalDigits + 1;
                if decimalDigits > 2 {
                    break;
                }
            }
        } else {
            break;
        }
        i := i + 1;
    }

    if dotIndex >= 0 && decimalDigits == 2 && i == |s| && |s| > 0 && s[0] != '.' {
        if |s| > 1 {
            result := s[0] == '0' || ('1' <= s[0] <= '9');
        } else {
            result := false;
        }
    } else {
        result := false;
    }
}
